using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    // Build adjacency list and reverse adjacency list
    unordered_map<long long, vector<pair<long long, long long>>> adj;
    unordered_map<long long, vector<pair<long long, long long>>> rev_adj;
    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long w = edge[2];
        adj[u].push_back({v, w});
        rev_adj[v].push_back({u, w});
    }

    // Dijkstra's algorithm with state tracking (node, switch_used)
    // Use a priority queue to track (cost, node, switch_used)
    // switch_used is a boolean indicating whether the switch at the node has been used
    // We use a 2D array to track the minimum cost to reach each node with or without using the switch
    vector<vector<long long>> dist(n, vector<long long>(2, LONG_MAX));
    dist[0][0] = 0;

    // Priority queue: [cost, node, switch_used]
    priority_queue<pair<long long, pair<long long, long long>>, vector<pair<long long, pair<long long, long long>>>, greater<>> pq;
    pq.push({0, {0, 0}});

    while (!pq.empty()) {
        long long cost = pq.top().first;
        long long u = pq.top().second.first;
        long long switch_used = pq.top().second.second;
        pq.pop();

        if (u == n - 1) {
            return cost;
        }

        // If we have already found a better path, skip
        if (cost > dist[u][switch_used]) {
            continue;
        }

        // Traverse the original edges
        for (auto& [v, w] : adj[u]) {
            long long new_cost = cost + w;
            if (new_cost < dist[v][switch_used]) {
                dist[v][switch_used] = new_cost;
                pq.push({new_cost, {v, switch_used}});
            }
        }

        // If the switch hasn't been used at u, consider reversing the edge
        if (!switch_used) {
            // Search for the original edge from v to u in the reverse adjacency list
            for (auto& [v, w] : rev_adj[u]) {
                long long new_cost = cost + 2 * w;
                if (new_cost < dist[v][1]) {
                    dist[v][1] = new_cost;
                    pq.push({new_cost, {v, 1}});
                }
            }
        }
    }

    // If we can't reach the destination
    return dist[n - 1][0] == LONG_MAX ? -1 : dist[n - 1][0];
}
